import os
import json
import base64
import hashlib
from datetime import datetime, timedelta
from urllib.parse import urlencode, urlparse, parse_qs

import requests
from flask import Flask, redirect, url_for, session, request, flash, render_template_string

app = Flask(__name__)
app.secret_key = os.urandom(24) # Replace with a strong, persistent key in production

# OIDC Provider Configuration (Replace with your actual OIDC provider details)
OIDC_PROVIDER_URL = "YOUR_OIDC_PROVIDER_URL"  # e.g., "https://accounts.google.com" or "https://your-keycloak-instance/realms/your-realm"
CLIENT_ID = "YOUR_CLIENT_ID"
REDIRECT_URI = "http://localhost:5000/oidc/callback" # Must match what's registered with the OIDC provider

# Discover OIDC configuration
# In a real application, you'd cache this or load from a config file
# For simplicity, we'll do it once at startup or on first request
OIDC_CONFIG = None

def discover_oidc_config():
    global OIDC_CONFIG
    if OIDC_CONFIG is None:
        discovery_url = f"{OIDC_PROVIDER_URL}/.well-known/openid-configuration"
        try:
            response = requests.get(discovery_url)
            response.raise_for_status()
            OIDC_CONFIG = response.json()
            print("OIDC Configuration Discovered:")
            print(json.dumps(OIDC_CONFIG, indent=2))
        except requests.exceptions.RequestException as e:
            print(f"Error discovering OIDC configuration: {e}")
            raise RuntimeError(f"Failed to discover OIDC configuration from {discovery_url}")
    return OIDC_CONFIG

# Helper to decode JWT (simplified, not for full validation)
def decode_jwt_part(token_part):
    # JWT parts are base64url encoded
    decoded_bytes = base64.urlsafe_b64decode(token_part + '==') # Add padding if missing
    return json.loads(decoded_bytes.decode('utf-8'))

# --- Flask Routes ---

@app.route('/')
def index():
    if 'user_info' in session:
        user_info = session['user_info']
        return render_template_string("""
            <h1>Welcome, {{ user_info.get('name', user_info.get('sub', 'User')) }}!</h1>
            <p>You are logged in.</p>
            <pre>{{ user_info | tojson(indent=2) }}</pre>
            <p><a href="{{ url_for('logout') }}">Logout</a></p>
        """, user_info=user_info)
    return render_template_string("""
        <h1>Welcome to the Admin Dashboard SSO</h1>
        <p>Please log in to continue.</p>
        <p><a href="{{ url_for('login') }}">Login with OIDC</a></p>
    """)

@app.route('/login')
def login():
    try:
        config = discover_oidc_config()
    except RuntimeError as e:
        flash(str(e), 'error')
        return redirect(url_for('index'))

    auth_endpoint = config.get('authorization_endpoint')
    if not auth_endpoint:
        flash("Authorization endpoint not found in OIDC configuration.", 'error')
        return redirect(url_for('index'))

    params = {
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'scope': 'openid profile email', # 'openid' is mandatory, 'profile' and 'email' are common
        'response_type': 'id_token',
        # 'nonce': 'some_random_nonce', # Skipping nonce for v1 as per requirements
        # 'state': 'some_random_state' # Recommended for CSRF protection
    }
    auth_url = f"{auth_endpoint}?{urlencode(params)}"
    return redirect(auth_url)

@app.route('/oidc/callback')
def oidc_callback():
    # OIDC Implicit Flow (response_type=id_token) returns parameters in the URL fragment
    # Flask's request.args only parses query parameters, not fragment.
    # We need JavaScript to read the fragment and send it to the server.
    # For simplicity in this Python-only example, we'll assume the fragment
    # has been processed by client-side JS and sent as query parameters.
    # In a real app, you'd have JS like:
    # if (window.location.hash) {
    #   const params = new URLSearchParams(window.location.hash.substring(1));
    #   window.location.replace('/oidc/callback?' + params.toString());
    # }

    # If the OIDC provider sends parameters directly in the query string (e.g., for error),
    # or if client-side JS has forwarded the fragment, they will be in request.args.
    id_token_jwt = request.args.get('id_token')
    error = request.args.get('error')
    error_description = request.args.get('error_description')

    if error:
        flash(f"OIDC Error: {error} - {error_description}", 'error')
        return redirect(url_for('index'))

    if not id_token_jwt:
        flash("No id_token received in callback.", 'error')
        return redirect(url_for('index'))

    try:
        # Basic ID Token parsing (NOT full validation)
        # In a real app, you MUST validate:
        # 1. Signature (using JWKS from OIDC config)
        # 2. 'iss' (issuer) matches OIDC_PROVIDER_URL
        # 3. 'aud' (audience) contains CLIENT_ID
        # 4. 'exp' (expiration) is in the future
        # 5. 'iat' (issued at) is not too old
        # 6. 'nonce' (if used) matches the one sent in the auth request
        # 7. 'azp' (authorized party) if present, matches CLIENT_ID

        parts = id_token_jwt.split('.')
        if len(parts) != 3:
            raise ValueError("Invalid ID Token format.")

        header = decode_jwt_part(parts[0])
        payload = decode_jwt_part(parts[1])

        # Basic checks (minimal for this example, expand significantly for production)
        if payload.get('iss') != OIDC_PROVIDER_URL:
            raise ValueError("ID Token issuer mismatch.")
        if CLIENT_ID not in payload.get('aud', []):
            raise ValueError("ID Token audience mismatch.")
        if datetime.fromtimestamp(payload.get('exp', 0)) < datetime.utcnow():
            raise ValueError("ID Token has expired.")

        # Store user info in session
        session['user_info'] = payload
        flash("Successfully logged in!", 'success')

    except Exception as e:
        flash(f"ID Token processing error: {e}", 'error')
        session.pop('user_info', None) # Clear any partial session data

    return redirect(url_for('index'))

